() => {
  const [axioms, setAxioms] = React.useState({ T: true, D: true, K4: false, K5: false });
  const n = 5;
  const labels = ['The', 'cat', 'sat', 'on', 'mat'];

  const genMatrix = () => {
    const m = Array.from({length: n}, () => Array(n).fill(0));
    // Base: random sparse attention
    for (let i = 0; i < n; i++) {
      for (let j = 0; j < n; j++) {
        m[i][j] = Math.random() > 0.6 ? Math.random() * 0.3 + 0.1 : 0.05;
      }
    }
    // Axiom T (reflexivity): strong diagonal
    if (axioms.T) for (let i = 0; i < n; i++) m[i][i] = 0.8 + Math.random() * 0.2;
    // Axiom D (seriality): ensure each row has at least one strong connection
    if (axioms.D) for (let i = 0; i < n; i++) {
      const j = Math.floor(Math.random() * n);
      m[i][j] = Math.max(m[i][j], 0.5);
    }
    // Axiom 4 (transitivity): if i→j and j→k, boost i→k
    if (axioms.K4) {
      for (let i = 0; i < n; i++)
        for (let j = 0; j < n; j++)
          if (m[i][j] > 0.3)
            for (let k = 0; k < n; k++)
              if (m[j][k] > 0.3) m[i][k] = Math.max(m[i][k], Math.min(m[i][j], m[j][k]));
    }
    // Axiom 5 (Euclidean): if i→j and i→k, then j→k
    if (axioms.K5) {
      for (let i = 0; i < n; i++)
        for (let j = 0; j < n; j++)
          if (m[i][j] > 0.3)
            for (let k = 0; k < n; k++)
              if (m[i][k] > 0.3) m[j][k] = Math.max(m[j][k], Math.min(m[i][j], m[i][k]));
    }
    // Normalize rows
    for (let i = 0; i < n; i++) {
      const s = m[i].reduce((a,b) => a+b, 0);
      for (let j = 0; j < n; j++) m[i][j] /= s;
    }
    return m;
  };

  const [matrix, setMatrix] = React.useState(genMatrix);
  React.useEffect(() => setMatrix(genMatrix()), [axioms.T, axioms.D, axioms.K4, axioms.K5]);

  const cellSize = 52;
  const logicName = axioms.T && axioms.K4 && axioms.K5 ? 'S5 (Knowledge)' :
    axioms.T && axioms.K4 ? 'S4 (Strong belief)' :
    axioms.D && !axioms.T ? 'KD (Deontic)' :
    axioms.T ? 'T (Factive)' : 'K (Basic modal)';

  return React.createElement('div', {style:{fontFamily:'monospace'}},
    React.createElement('div', {style:{display:'flex',gap:16,marginBottom:16,flexWrap:'wrap'}},
      ...Object.entries({T:'Reflexive (T)',D:'Serial (D)',K4:'Transitive (4)',K5:'Euclidean (5)'}).map(([k,label]) =>
        React.createElement('label', {key:k, style:{display:'flex',alignItems:'center',gap:6,cursor:'pointer',color:'#e2e8f0',fontSize:14}},
          React.createElement('input', {type:'checkbox', checked:axioms[k], onChange:()=>setAxioms(p=>({...p,[k]:!p[k]}))}),
          label
        )
      )
    ),
    React.createElement('div', {style:{marginBottom:12,color:'#a78bfa',fontWeight:'bold',fontSize:16}}, `Logic: ${logicName}`),
    React.createElement('div', {style:{display:'flex',gap:8,alignItems:'flex-start'}},
      React.createElement('div', null,
        React.createElement('div', {style:{display:'flex',marginLeft:52}},
          ...labels.map((l,j) => React.createElement('div', {key:j, style:{width:cellSize,textAlign:'center',fontSize:11,color:'#94a3b8'}}, l))
        ),
        ...matrix.map((row, i) =>
          React.createElement('div', {key:i, style:{display:'flex',alignItems:'center'}},
            React.createElement('div', {style:{width:48,textAlign:'right',paddingRight:4,fontSize:11,color:'#94a3b8'}}, labels[i]),
            ...row.map((v, j) => {
              const intensity = Math.round(v * 255);
              return React.createElement('div', {
                key:j,
                style:{
                  width:cellSize, height:cellSize-4,
                  backgroundColor:`rgba(139,92,246,${v})`,
                  border:'1px solid rgba(139,92,246,0.2)',
                  display:'flex',alignItems:'center',justifyContent:'center',
                  fontSize:11, color: v > 0.4 ? '#fff' : '#94a3b8'
                }
              }, v.toFixed(2));
            })
          )
        )
      )
    ),
    React.createElement('button', {
      onClick: () => setMatrix(genMatrix()),
      style:{marginTop:12,padding:'6px 16px',background:'#7c3aed',color:'white',border:'none',borderRadius:6,cursor:'pointer',fontSize:13}
    }, '🔄 Regenerate')
  );
}

() => {
  const [roles, setRoles] = React.useState(['epistemic', 'temporal', 'deontic', 'epistemic']);
  const roleColors = { epistemic: '#8b5cf6', temporal: '#06b6d4', deontic: '#f59e0b', causal: '#ef4444' };
  const roleIcons = { epistemic: '🧠', temporal: '⏰', deontic: '⚖️', causal: '🔗' };
  const allRoles = ['epistemic', 'temporal', 'deontic', 'causal'];

  const capabilities = {
    epistemic: ['fact lookup', 'entity tracking', 'set membership'],
    temporal: ['sequence ordering', 'past reference', 'event ordering'],
    deontic: ['pattern completion', 'grammar enforcement', 'format following'],
    causal: ['if-then reasoning', 'intervention prediction', 'counterfactual']
  };

  const getCombinedCapabilities = () => {
    const caps = new Set();
    roles.forEach(r => capabilities[r].forEach(c => caps.add(c)));
    return [...caps];
  };

  const getEmergent = () => {
    const r = new Set(roles);
    const e = [];
    if (r.has('epistemic') && r.has('temporal')) e.push('📖 Narrative comprehension (know WHAT happened WHEN)');
    if (r.has('epistemic') && r.has('deontic')) e.push('✅ Instruction following (know facts + follow rules)');
    if (r.has('temporal') && r.has('causal')) e.push('🔮 Prediction (temporal order + causal mechanism)');
    if (r.has('epistemic') && r.has('causal')) e.push('💡 Explanation (know facts + trace causes)');
    if (r.size >= 3) e.push('🌟 Theory of Mind (multiple modal perspectives)');
    return e;
  };

  return React.createElement('div', {style:{fontFamily:'system-ui',color:'#e2e8f0'}},
    React.createElement('div', {style:{display:'flex',gap:12,marginBottom:20,flexWrap:'wrap'}},
      roles.map((role, i) =>
        React.createElement('div', {key:i, style:{background:'rgba(30,30,50,0.8)',borderRadius:12,padding:'12px 16px',border:`2px solid ${roleColors[role]}`,minWidth:120}},
          React.createElement('div', {style:{fontSize:12,color:'#94a3b8',marginBottom:4}}, `Head ${i}`),
          React.createElement('div', {style:{fontSize:20,marginBottom:6}}, roleIcons[role]),
          React.createElement('select', {
            value: role,
            onChange: e => { const nr = [...roles]; nr[i] = e.target.value; setRoles(nr); },
            style:{background:'#1e1e3a',color:'#e2e8f0',border:'1px solid #4a4a6a',borderRadius:4,padding:'2px 6px',fontSize:12,width:'100%'}
          }, allRoles.map(r => React.createElement('option', {key:r, value:r}, r)))
        )
      )
    ),
    React.createElement('div', {style:{marginBottom:16}},
      React.createElement('div', {style:{fontSize:13,fontWeight:'bold',color:'#a78bfa',marginBottom:6}}, 'Individual Capabilities:'),
      React.createElement('div', {style:{display:'flex',flexWrap:'wrap',gap:6}},
        getCombinedCapabilities().map(c =>
          React.createElement('span', {key:c, style:{background:'rgba(139,92,246,0.15)',padding:'3px 10px',borderRadius:12,fontSize:12,color:'#c4b5fd'}}, c)
        )
      )
    ),
    React.createElement('div', null,
      React.createElement('div', {style:{fontSize:13,fontWeight:'bold',color:'#f59e0b',marginBottom:6}}, 'Emergent from Combination:'),
      getEmergent().length > 0 ?
        getEmergent().map(e => React.createElement('div', {key:e, style:{fontSize:13,padding:'4px 0',color:'#fcd34d'}}, e)) :
        React.createElement('div', {style:{fontSize:13,color:'#6b7280',fontStyle:'italic'}}, 'Add diverse modal types for emergent capabilities...')
    )
  );
}
